mapper.insert:
/** UsptBsnsCnvnDao.insert */
insert into uspt_bsns_cnvn
			(
				bsns_cnvn_id						/*사업협약ID*/
				, apply_id							 /*신청ID*/
				, cnvn_sttus_cd                  /*협약상태코드(G:CNVN_STTUS)*/
				, cnvn_de                        /*협약일자*/
				, cnvn_bgnde                     /*협약시작일*/
				, cnvn_endde                     /*협약종료일*/
				, cnvn_bdt                       /*협약서본문*/
				, bsnm_sign_dt                   /*사업자서명일시(주관업체)*/
				, bsns_mgc_sign_dt               /*사업단서명일시*/
				, cnvn_trmnat_de                 /*협약해지일*/
				, cnvn_trmnat_div_cd             /*협약해지구분코드*/
				, redemp_trgamt                  /*환수대상금액*/
				, redemp_compt_amount            /*환수완료금액*/
				, redemp_de                      /*환수일*/
				, cnvn_trmnat_resn_cn            /*협약해지사유내용*/
				, cnvn_file_group_id             /*협약파일그룹ID*/
				, cnvn_trmnat_file_group_id      /*협약해지첨부파일그룹ID*/
				, bsns_plan_doc_id               /*사업계획서ID*/
				, bsns_mgc_sign_id               /*사업단서명ID*/
				, bsns_mgc_nm                    /*사업단명*/
				, bsns_mgc_ceo_nm                /*사업단대표자명*/
				, bsns_mgc_bizrno                /*사업단사업자번호*/
				, creator_id
				, created_dt
				, updater_id
				, updated_dt
				)
				values(
				  #{bsnsCnvnId}
				, #{applyId}
				, #{cnvnSttusCd}
				, #{cnvnDe}
				, #{cnvnBgnde}
				, #{cnvnEndde}
				, #{cnvnBdt}
				, #{bsnmSignDt}
				, #{bsnsMgcSignDt}
				, #{cnvnTrmnatDe}
				, #{cnvnTrmnatDivCd}
				, #{redempTrgamt}
				, #{redempComptAmount}
				, #{redempDe}
				, #{cnvnTrmnatResnCn}
				, #{cnvnFileGroupId}
				, #{cnvnTrmnatFileGroupId}
				, #{bsnsPlanDocId}
				, #{bsnsMgcSignId}
				, #{bsnsMgcNm}
				, #{bsnsMgcCeoNm}
				, #{bsnsMgcBizrno}
				, #{creatorId}
				, #{createdDt}
				, #{updaterId}
				, #{updatedDt}
				)

mapper.delete:
/** UsptBsnsCnvnDao.deleteByBsnsPlanDocId */
delete from uspt_bsns_cnvn
		where bsns_plan_doc_id = #{bsnsPlanDocId}

mapper.select:
/** UsptBsnsCnvnDao.selectBsnsCnvnListCnt */ select count(1) from uspt_bsns ub /**사업*/ inner join uspt_bsns_pblanc ubp /**사업공고*/ on ub.bsns_cd = ubp.bsns_cd and ubp.enabled = true inner join uspt_bsns_pblanc_applcnt ubpa /**사업공고신청자*/ on ubp.pblanc_id = ubpa.pblanc_id /*공공id*/ inner join uspt_bsns_pblanc_apply_task ubpat /**사업공고 신청 과제*/ on ubpa.apply_id = ubpat.apply_id inner join uspt_bsns_cnvn ubc /*사업협약*/ on ubpat.apply_id = ubc.apply_id inner join uspt_bsns_plan_doc ubpd /**사업계획서*/ on ubc.bsns_plan_doc_id = ubpd.bsns_plan_doc_id inner join uspt_task_rspnber utr /**과제책임자*/ on ubpd.bsns_plan_doc_id = utr.bsns_plan_doc_ID where 1=1
and ubc.cnvn_de between #{cnvnDeStart} and #{cnvnDeEnd}
and ubc.cnvn_sttus_cd = #{cnvnSttusCd} /*협약상태코드*/
and ubc.cnvn_sttus_cd in ('CNST03', 'CNST04', 'CNST05') /* 서면요청, 서명완료, 협약완료*/
and ub.bsns_nm like concat('%', #{bsnsNm}, '%') /*사업명*/
and ubpd.task_nm_ko like concat('%', #{taskNmKo}, '%') /*과제명*/

/** UsptBsnsCnvnDao.selectFrontBsnsCnvnList */ select a.* , row_number() over (order by a.receipt_no desc) as rn from ( select ub.bsns_nm /*사업명*/ , ub.bsns_year /*사업년도*/ , ubpa.receipt_no /*접수번호*/ , ubp.pblanc_nm /*공고명*/ , ubpd.task_nm_ko /*과제명*/ , utr.rspnber_nm /*책임자명*/ , ubc.cnvn_sttus_cd /*협약상태코드(G:CNVN_STTUS)*/ , fn_cmm_get_code_nm('CNVN_STTUS', ubc.cnvn_sttus_cd) as cnvn_sttus_nm /*협약상태명*/ , ubc.bsns_cnvn_id /*사업협약ID */ , ubc.apply_id /** 신청ID */ , ubc.bsns_plan_doc_id /*사업계획서ID*/ from uspt_bsns ub /**사업*/ inner join uspt_bsns_pblanc ubp /**사업공고*/ on ub.bsns_cd = ubp.bsns_cd and ubp.enabled = true inner join uspt_bsns_pblanc_applcnt ubpa /**사업공고신청자*/ on ubp.pblanc_id = ubpa.pblanc_id /*공공id*/ inner join uspt_bsns_cnvn ubc /*사업협약*/ on ubpa.apply_id = ubc.apply_id inner join uspt_bsns_plan_doc ubpd /**사업계획서*/ on ubc.bsns_plan_doc_id = ubpd.bsns_plan_doc_id inner join uspt_task_rspnber utr /**과제책임자*/ on ubpd.bsns_plan_doc_id = utr.bsns_plan_doc_ID where 1=1
and ubc.cnvn_de between #{cnvnDeStart} and #{cnvnDeEnd}
and ubc.cnvn_sttus_cd = #{cnvnSttusCd} /*협약상태코*/
and ubc.cnvn_sttus_cd in ('CNST03', 'CNST04', 'CNST05') /* 서면요청, 서명완료, 협약완료*/
and ub.bsns_nm like concat('%', #{bsnsNm}, '%') /*사업명*/
and ubpd.task_nm_ko like concat('%', #{taskNmKo}, '%') /*과제명*/
) a where 1=1 offset #{beginRowNum} -1 limit #{itemsPerPage}

mapper.update:
/** UsptBsnsCnvnDao.updateCnvnFileGroupId */
	update uspt_bsns_cnvn
	 	 set  cnvn_file_group_id = #{cnvnFileGroupId}
		  	 , updater_id       = #{updaterId}
			 , updated_dt      = #{updatedDt}
	where bsns_cnvn_id 		= #{bsnsCnvnId}
   	  and apply_id 			= #{applyId}

/** UsptBsnsCnvnDao.updateBsnmSignDt */
	update uspt_bsns_cnvn
	 	 set  bsnm_sign_dt =  #{bsnmSignDt}
		  	 , updater_id       = #{updaterId}
			 , updated_dt      = #{updatedDt}
	where bsns_cnvn_id 		= #{bsnsCnvnId}
   	  and apply_id 			= #{applyId}

/** UsptBsnsCnvnDao.updateCnvnSttus */
	update uspt_bsns_cnvn
	 	 set  cnvn_sttus_cd = #{cnvnSttusCd}
		  	 , updater_id       = #{updaterId}
			 , updated_dt      = #{updatedDt}
	where bsns_cnvn_id 		= #{bsnsCnvnId}
   	  and apply_id 			= #{applyId}

mapper.select:
/** UsptBsnsCnvnDao.selectBsnsCnvnList */ select a.* , row_number() over (order by a.receipt_no desc) as rn from ( select ub.bsns_nm /*사업명*/ , ub.bsns_year /*사업년도*/ , ubpa.receipt_no /*접수번호*/ , ubp.pblanc_nm /*공고명*/ , ubpd.task_nm_ko /*과제명*/ , ubc.cnvn_sttus_cd /*협약상태코드(G:CNVN_STTUS)*/ , fn_cmm_get_code_nm('CNVN_STTUS', ubc.cnvn_sttus_cd) as cnvn_sttus_nm /*협약상태명*/ , (select member_nm from cmmt_member where member_id = ubpd.member_id ) as member_nm /*사업자명(주관사명)*/ , ubc.cnvn_de /*협약일자*/ , ubc.cnvn_trmnat_de /*협약해지일*/ , utr.rspnber_nm /*과제책임자명*/ , ubc.bsns_cnvn_id /*사업협약ID */ , ubc.apply_id /* 신청ID */ , ubc.bsns_plan_doc_id /*사업계획서ID*/ from uspt_bsns ub /**사업*/ inner join uspt_bsns_pblanc ubp /**사업공고*/ on ub.bsns_cd = ubp.bsns_cd and ubp.enabled = true inner join uspt_bsns_pblanc_applcnt ubpa /**사업공고신청자*/ on ubp.pblanc_id = ubpa.pblanc_id /*공공id*/ inner join uspt_bsns_cnvn ubc /*사업협약*/ on ubpa.apply_id = ubc.apply_id inner join uspt_bsns_plan_doc ubpd /**사업계획서*/ on ubc.bsns_plan_doc_id = ubpd.bsns_plan_doc_id inner join uspt_task_rspnber utr /**과제책임자*/ on ubpd.bsns_plan_doc_id = utr.bsns_plan_doc_ID where 1=1
and ub.bsns_year = #{bsnsYear} /*사업년도*/
and ub.bsns_nm like concat('%', #{bsnsNm}, '%') /*사업명*/
and ubc.cnvn_sttus_cd = #{cnvnSttusCd} /*협약상태코드*/
and ubc.cnvn_de between #{cnvnDeStart} and #{cnvnDeEnd} /*협약일자*/
and ubpd.task_nm_ko like concat('%', #{taskNmKo}, '%') /*과제명*/
and utr.rspnber_nm like concat('%', #{rspnberNm}, '%') /*과제책임자명*/
) a where 1=1
and a.member_nm like concat('%', #{memberNm}, '%') /*주관업체명*/
offset #{beginRowNum} -1 limit #{itemsPerPage}

mapper.update:
	/** UsptBsnsCnvnDao.updateCnvnCnclsComplete */
		update  uspt_bsns_cnvn
 			  set   cnvn_sttus_cd			=	#{cnvnSttusCd}   		/*협약상태코드(G:CNVN_STTUS)*/
					 , bsns_mgc_sign_dt	= #{bsnsMgcSignDt}	/*사업단서명일시*/
					 , bsns_mgc_sign_id	= #{bsnsMgcSignId} 	/*사업단서명ID*/
					 , updater_id   		 = #{updaterId}
	 				 , updated_dt       	 = #{updatedDt}
			where bsns_cnvn_id			 = #{bsnsCnvnId}			/*사업협약ID*/
	  		   and apply_id				 = #{applyId}				 /*신청ID*/

	/** UsptBsnsCnvnDao.updateCnvnCnclsInit */
		update  uspt_bsns_cnvn
 			  set   cnvn_sttus_cd			=	#{cnvnSttusCd}   		/*협약상태코드(G:CNVN_STTUS)*/
					 , bsnm_sign_dt		= #{bsnmSignDt}			/*사업자서명일시*/
					 , updater_id   		 = #{updaterId}
	 				 , updated_dt       	 = #{updatedDt}
			where bsns_cnvn_id			 = #{bsnsCnvnId}			/*사업협약ID*/
	  		   and apply_id				 = #{applyId}				 /*신청ID*/

/** UsptBsnsCnvnDao.updateCnvnSttus */
	update uspt_bsns_cnvn
	 	 set  cnvn_sttus_cd = #{cnvnSttusCd}
	 	 	 , cnvn_trmnat_div_cd = #{cnvnTrmnatDivCd}
		  	 , updater_id       = #{updaterId}
			 , updated_dt      = #{updatedDt}
	where bsns_cnvn_id 		= #{bsnsCnvnId}
   	  and apply_id 			= #{applyId}
